var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록……! 하악……! 하아……!","JPN":"ゴホッ……！　はあっ……！　はあ……！","ENG":"*Cough...!* *Huff...!* *Huff...!*","TWN":"咳咳……！哈啊……！哈啊……！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 호흡이 계속 멎고 있어. 역시 이건 감기라기엔…….","JPN":"マクレディー君、咳で呼吸ができないでいる。さすがにこれは風邪では……","ENG":"Regina, your breathing is irregular. I should've known this wasn't a cold...!","TWN":"麥克蕾蒂，呼吸速度一直在減緩，如果這是感冒也太……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"실제로 상대해 본 소감은 어떻소, 부학회장?","JPN":"実際に相手してみた感想はどうだ、副学会長。","ENG":"What is your impression of fighting one of them, Vice President?","TWN":"實際體驗後感覺怎麼樣，副學會長？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"생물로서의 퍼포먼스를 전투에만 투자한 결과물이오. 감상을 들려 주면 좋겠군.","JPN":"生物としてのパフォーマンスを戦闘だけに結集させた賜物だ。感想を聞かせてほしいな。","ENG":"They are the result of investing every bit of performance for battle. I'd love to hear your input.","TWN":"這是把生物科技投入到戰鬥中的成果。希望你能說出你的感想。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"호, 혼자서는 더 이상 무리예요. 루나 님도 저쪽으로 돌아서셨잖아요.","JPN":"ひ、一人ではもう無理です。ルナ様もあっち側につかれたじゃないですか。","ENG":"Y-you can't fight them all on her own. Even Ms. Luna turned against us.","TWN":"你…你一個人撐不住的。露娜不是也投向那邊了嘛。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"기관 사람이면 학회를 괴롭히는 나쁜 악당이라고요! 레지나 님이 감싸 주실 필요는……!","JPN":"機関の人といえば学会をいじめるひどい悪党です！　レジーナ様が庇ってさしあげる必要は……！","ENG":"Institution agents are villains who prey on the Society! You have no reason to protec–!","TWN":"機關的人一直是阻礙學會的礙事者！蕾佳娜大人沒必要保護……！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 저는…… 저 자들이 저지르는 미친 짓을 도저히 납득할 수 없어요.","JPN":"いいえ。私は……あの者たちの狂気じみた行動を納得することは到底できませんわ。","ENG":"No. But I... I cannot possibly accept the insanity they have caused.","TWN":"不，我……我實在無法接受他們做出的瘋狂行為。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……가문의 명예를 위해서라도.","JPN":"……家門の名誉のためにも。","ENG":"...This is my way of protecting my family's honor.","TWN":"……哪怕是為了家族的榮譽。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠. 상식이니 윤리니 떠들어댈 때보다는 좋은 눈빛이로군.","JPN":"ふむ。常識だの倫理だのと話していたときよりは、いい目をしている。","ENG":"Hmm... I like this version of you better than the one where you were ranting about ethics and common sense.","TWN":"嗯，我喜歡你現在的眼神，比起高談闊論什麼常識和倫理的時候，強多了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하지만 수적으로도 열세인 마당에 계속 버틸 수 있겠소?","JPN":"だが数的にも劣勢であるこの状況で、これ以上耐えられるのか？","ENG":"But how much longer can you endure? You are obviously outnumbered.","TWN":"不過在數量上處於劣勢的情況下，你還能撐多久呢？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님…….","JPN":"副学会長様……","ENG":"Ms. Vice President...","TWN":"副學會長……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"소장님, 슬슬 그만 가지고 놀고 이만 마무리하는 게 어때?","JPN":"所長、そろそろ弄ぶのはやめてもう終わりにしたらどう？","ENG":"Chief Heydrich, why don't you stop fooling around and wrap it up already?","TWN":"所長，別再繼續玩了，現在結束戰鬥怎麼樣？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"집 나간 꼬마도 돌아왔겠다, 의식이 지연되면 학회장님도 심기가 불편해지실 것 같은데.","JPN":"家出したガキも戻ってきたし、儀式が遅れたら学会長もご機嫌斜めになるはずだわ。","ENG":"Our little runaway has returned home, and the President will be upset if the ritual is delayed any longer.","TWN":"離家出走的小鬼應該也回來了，儀式推遲的話，學會長也會不高興的。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰, 셰나. 그래도 부학회장인데, 살살…….","JPN":"しぇ、シェナ。相手は副学会長なんだし、優しく……","ENG":"S-Shena. But she is still the Vice President. Shouldn't we–","TWN":"世…世娜，她可是副學會長，拜託你……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어른들 일이야. 모르면 조용히나 있어, 꼬마야.","JPN":"大人同士の話よ。何も知らないなら静かにしてなさい、ガキ。","ENG":"Adults are talking right now, child. So behave and keep your mouth shut.","TWN":"這是大人的事，不懂的話就閉嘴，小鬼。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"흠. 타당한 지적이오.","JPN":"ふむ。もっともな指摘だ。","ENG":"Hmm... A valid point.","TWN":"嗯，這個指責很合理。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"모처럼 맥크레디 집안 사람다운 독기를 보여 줬는데, 아쉽군.","JPN":"せっかくマクレディー家らしい毒気を見せてくれたが、残念だな。","ENG":"It's a shame it has to end here, because you've demonstrated ruthlessness worthy of a MacCready.","TWN":"副學會長難得表現出了麥克蕾蒂家族的狠勁，真是可惜。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};